func doApplicationService_UpdateApplication(getCfg func() *config.Config, getOutput func() string, cmd *cobra.Command, req *applicationpb.UpdateApplicationRequest) error {
	dryRun, _ := cmd.Flags().GetBool("dry-run")
	if dryRun {
		reqJSON, err := protojson.MarshalOptions{Indent: "  "}.Marshal(req)
		if err != nil {
			return fmt.Errorf("marshalling request: %w", err)
		}
		envelope := map[string]json.RawMessage{
			"method":  json.RawMessage(fmt.Sprintf("%q", "zitadel.application.v2.ApplicationService/UpdateApplication")),
			"request": json.RawMessage(reqJSON),
		}
		out, _ := json.MarshalIndent(envelope, "", "  ")
		fmt.Println(string(out))
		return nil
	}

	cfg := getCfg()
	actx, _, err := config.ActiveCtx(cfg)
	if err != nil {
		return err
	}
	tokenSource, err := auth.TokenSource(cmd.Context(), actx)
	if err != nil {
		return err
	}
	httpClient := client.New(tokenSource)
	baseURL := client.InstanceURL(actx.Instance)
	svcClient := applicationconnect.NewApplicationServiceClient(httpClient, baseURL)

	resp, err := svcClient.UpdateApplication(cmd.Context(), connect.NewRequest(req))
	if err != nil {
		return FormatConnectError(err)
	}

	if getOutput() == "json" {
		return output.JSON(resp.Msg)
	}

	header := []string{"CHANGE DATE"}
	rows := [][]string{
		{
			func() string {
				if t := resp.Msg.GetChangeDate(); t != nil {
					return t.AsTime().Format("2006-01-02T15:04:05Z")
				}
				return ""
			}(),
		},
	}
	output.Table(header, rows)
	return nil
}

